    ]
  );

  const onConfirmUpsell = useCallback(
    (frequency: string, amount?: number) => {
      if (amount) {
        const total = capturedSubmission!.amountAllocationsAttributes!.reduce(
          (sum, allocation) => sum + allocation.amount,
          0
        );

        const newAmountAllocationsAttributes = capturedSubmission!.amountAllocationsAttributes!.map(
          (allocation) => ({ ...allocation, amount: (allocation.amount / total) * amount })
        );

        // Check if we are short or over due to rounding and adjust using first fund
        const newTotal = newAmountAllocationsAttributes.reduce((acc, x) => acc + x.amount, 0);

        if (amount - newTotal > 0) {
          newAmountAllocationsAttributes[0].amount += amount - newTotal;
        } else if (amount - newTotal < 0) {
          newAmountAllocationsAttributes[0].amount += amount - newTotal;
        }

        const submission: ActionPageSubmissionForm = {
          ...capturedSubmission,
          amountAllocationsAttributes: newAmountAllocationsAttributes,
          frequency,
        };

        onSubmit(submission);
      } else {
        onSubmit(capturedSubmission!);
      }

      onClosePreConversionUpsell();
    },
    [capturedSubmission, onClosePreConversionUpsell, onSubmit]
  );

  const onDeclineUpsell = useCallback(() => {
    onSubmit(capturedSubmission!);
    onClosePreConversionUpsell();
