import currency from 'currency.js';

/**
 * Default behavior is to show cents always
 *   - 1298 => $12.98
 *   - 1200 => $12.00
 *
 * With `opts.hideDecimal`, you can opt to hide cents if equal to 0
 *   - 1298 => $12.98
 *   - 1200 => $12
 */

type FormatCurrencyOptions = {
  accountingStyle?: boolean;
  hideDecimal?: boolean;
  hideDollarSign?: boolean;
  useGrouping?: boolean;
};

const formatCurrencyDefaultOptions: FormatCurrencyOptions = {
  accountingStyle: false,
  hideDecimal: false,
  hideDollarSign: false,
  useGrouping: true,
};

export const formatCurrency = (cents: number, opts?: FormatCurrencyOptions): string => {
  const options = { ...formatCurrencyDefaultOptions, ...opts };
  const sanitizedCents = cents + 0; // If cents is -0 forces +0
  const hasCents = cents % 100 > 0;
  const digits = !hasCents && options.hideDecimal ? 0 : undefined;

  const formatted = new Intl.NumberFormat('en-US', {
    currency: 'USD',
    currencySign: options.accountingStyle ? 'accounting' : 'standard',
    maximumFractionDigits: digits,
    minimumFractionDigits: digits,
    style: 'currency',
    useGrouping: options.useGrouping,
  }).format(sanitizedCents / 100);

  return options?.hideDollarSign ? formatted.replace('$', '') : formatted;
};

// Formats a value with no symbol or group separators, i.e. $10,000,000.26 as 10000000.26
export const formatCurrencyForPayment = (cents: number) => {
  const sanitizedCents = cents + 0; // If cents is -0 forces +0
  return currency(sanitizedCents / 100, { decimal: '.', separator: '', symbol: '' }).format();
};

